// Calculer les dates de la semaine précédente
const maintenant = new Date();
const lundiCette = new Date(maintenant);
lundiCette.setDate(maintenant.getDate() - maintenant.getDay() + 1);

const lundiPrecedent = new Date(lundiCette);
lundiPrecedent.setDate(lundiCette.getDate() - 7);
const dimanchePrecedent = new Date(lundiPrecedent);
dimanchePrecedent.setDate(lundiPrecedent.getDate() + 6);

const formatDate = (d) => d.toLocaleDateString('fr-FR', { day: '2-digit', month: 'long' });

return [{
  json: {
    semaine: `${formatDate(lundiPrecedent)} – ${formatDate(dimanchePrecedent)}`,
    debutISO: lundiPrecedent.toISOString(),
    finISO: dimanchePrecedent.toISOString(),
    annee: maintenant.getFullYear(),
    numeroSemaine: Math.ceil((maintenant - new Date(maintenant.getFullYear(), 0, 1)) / (7 * 24 * 60 * 60 * 1000))
  }
}];

// Consolider toutes les données du rapport
const dates = $('Calculer Période S-1').first().json;
const factures = $('Freebe — CA Semaine').all().map(i => i.json);
const tickets = $('Linear — Tickets Semaine').all().map(i => i.json);

// CA semaine
const caSemaine = factures.reduce((sum, f) => sum + (f.amount || 0), 0);
const nbFactures = factures.length;

// Analyse tickets Linear
const ticketsParStatut = {};
tickets.forEach(t => {
  const statut = t.state?.name || 'Inconnu';
  ticketsParStatut[statut] = (ticketsParStatut[statut] || 0) + 1;
});
const ticketsDone = ticketsParStatut['Done'] || ticketsParStatut['Terminé'] || 0;
const ticketsEnCours = ticketsParStatut['In Progress'] || ticketsParStatut['En cours'] || 0;
const ticketsOuverts = Object.values(ticketsParStatut).reduce((a,b) => a+b, 0);

// Formatage
const formatEuro = (n) => new Intl.NumberFormat('fr-FR', { style: 'currency', currency: 'EUR' }).format(n);

const statutsTable = Object.entries(ticketsParStatut)
  .map(([k,v]) => `| ${k} | ${v} |`).join('\n');

return [{
  json: {
    semaine: dates.semaine,
    numeroSemaine: dates.numeroSemaine,
    caSemaine: formatEuro(caSemaine),
    caRaw: caSemaine,
    nbFactures,
    ticketsOuverts,
    ticketsDone,
    ticketsEnCours,
    statutsTable,
    clients: factures.map(f => f.client?.name || 'N/A').join(', ') || 'Aucun'
  }
}];
